#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__kernel void dynproc_kernel(
    const int pyramid_height,
    __global const int* wall,
    __global int* src,
    __global int* dst,
    const int cols,
    const int rows,
    const int t_start,
    const int borderCols,
    const int theHalo,
    __local int* localSrc1,
    __local int* localSrc2,
    __global int* outputBuffer)
{
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int group_size = get_local_size(0);

    // Compute start and end cols for this workgroup
    int start_col = gid;
    int row_offset = t_start;

    // Each work item processes one element per time step within the pyramid height
    for (int i = 0; i < pyramid_height; i++) {
        int cur_row = row_offset + i + 1;
        if (cur_row >= rows) break;

        // Load neighbors from src to local memory with halo
        // We will use local memory to reduce global memory accesses

        // Compute local index with halo offset
        int local_idx = lid + theHalo;

        // Load central element
        if (gid < cols)
            localSrc1[local_idx] = src[gid];
        else
            localSrc1[local_idx] = INT_MAX;

        // Load halo elements
        if (lid < theHalo) {
            int left_idx = gid - theHalo;
            int right_idx = gid + group_size;

            localSrc1[local_idx - theHalo] = (left_idx >= 0) ? src[left_idx] : INT_MAX;
            localSrc1[local_idx + group_size] = (right_idx < cols) ? src[right_idx] : INT_MAX;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (gid < cols) {
            int min_val = localSrc1[local_idx];
            if (local_idx - 1 >= 0)
                min_val = min(min_val, localSrc1[local_idx - 1]);
            if (local_idx + 1 < group_size + 2 * theHalo)
                min_val = min(min_val, localSrc1[local_idx + 1]);

            dst[gid] = wall[cur_row * cols + gid] + min_val;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        // Swap localSrc buffers for next iteration, but since we only have one localSrc1, we just overwrite
        // Swap src and dst pointers for next iteration on host side, so here we just update src accordingly
        barrier(CLK_GLOBAL_MEM_FENCE);
        // No swap here in kernel; swapping happens on host side
    }
}
